class TransformManyVectors(Scene):
    CONTENT_CENTER = DOWN * 0.5

    def construct(self):
        vectors = VGroup(*[
            Vector([x, y])
            for x in np.arange(-int(FRAME_X_RADIUS) + 0.5, int(FRAME_X_RADIUS) + 0.5)
            for y in np.arange(-int(FRAME_Y_RADIUS) + 0.5, int(FRAME_Y_RADIUS) + 0.5)
        ])
        vectors.set_submobject_colors_by_gradient(PINK, YELLOW)
        t_matrix = [[2, 1], [1, 2]]
        transformed_vectors = VGroup(*[
            Vector(
                np.dot(np.array(t_matrix).transpose(), vect.get_end()[:2]),
                color=vect.get_color()
            )
            for vect in vectors
        ])
        self.play(Create(vectors, lag_ratio=0.5))
        self.wait()
        self.play(Transform(
            vectors, transformed_vectors,
            run_time=3,
            path_arc=-np.pi/2
        ))
        self.wait()
